const Icon: React.FC<IconProps> = ({
  iconName = '',
  rotate = false,
  wrapped = false,
}) => {
  if (!iconsMap[iconName]) {
    return null;
  }

  if (!wrapped) {
    return iconsMap[iconName];
  }

  return (
    <Styled.Icon $rotate={rotate}>
      {iconsMap[iconName]}
    </Styled.Icon>
  );
};

export default memo(Icon);
